import { describe, it, expect } from 'vitest';
import {
  isValidOrderStatusTransition,
  validateOrderItems,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('isValidOrderStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidOrderStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidOrderStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidOrderStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidOrderStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidOrderStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidOrderStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidOrderStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidOrderStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidOrderStatusTransition('delivered', 'confirmed')).toBe(false);
      expect(isValidOrderStatusTransition('delivered', 'shipped')).toBe(false);
      expect(isValidOrderStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidOrderStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidOrderStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidOrderStatusTransition('cancelled', 'shipped')).toBe(false);
      expect(isValidOrderStatusTransition('cancelled', 'delivered')).toBe(false);
    });

    it('should reject same-state transitions', () => {
      expect(isValidOrderStatusTransition('pending', 'pending')).toBe(false);
      expect(isValidOrderStatusTransition('confirmed', 'confirmed')).toBe(false);
    });
  });

  describe('validateOrderItems', () => {
    it('should return null for valid items', () => {
      const items = [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ];
      expect(validateOrderItems(items)).toBeNull();
    });

    it('should return error for empty items array', () => {
      expect(validateOrderItems([])).toBe('Order must have at least one item');
    });

    it('should return null for multiple items', () => {
      const items = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 5 },
      ];
      expect(validateOrderItems(items)).toBeNull();
    });
  });
});

import { describe, it, expect } from 'vitest';
import { isValidEmail } from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('isValidEmail', () => {
    it('should accept valid email addresses', () => {
      expect(isValidEmail('alice@example.com')).toBe(true);
      expect(isValidEmail('bob.smith@company.org')).toBe(true);
      expect(isValidEmail('user+tag@domain.co')).toBe(true);
    });

    it('should reject email without @', () => {
      expect(isValidEmail('aliceexample.com')).toBe(false);
    });

    it('should reject email without domain', () => {
      expect(isValidEmail('alice@')).toBe(false);
    });

    it('should reject email without local part', () => {
      expect(isValidEmail('@example.com')).toBe(false);
    });

    it('should reject email without TLD', () => {
      expect(isValidEmail('alice@example')).toBe(false);
    });

    it('should reject empty string', () => {
      expect(isValidEmail('')).toBe(false);
    });

    it('should reject email with spaces', () => {
      expect(isValidEmail('alice @example.com')).toBe(false);
      expect(isValidEmail('alice@ example.com')).toBe(false);
    });
  });
});

